#include<bits/stdc++.h>
using namespace std;
const int N = 2e5+5;
long long n,m,p[N],l,r,res;
priority_queue<long long> q;
bool check(long long Max){
    long long cnt=0;
    long long sum=0;
    for(int i=1;i<=n;i++){
        long long tmp=(Max+p[i])/(2*p[i]);
        cnt+=tmp;
        if(sqrt(m/p[i])<tmp)return 0;
        sum+=tmp*tmp*p[i];
        if(sum>m)return 0;
    }
    return sum<=m;
}
int main(){
    cin>>n>>m;l=0,r=m;
    for(int i=1;i<=n;i++)cin>>p[i];
    sort(p+1,p+n+1);
    while(l<=r){
        long long mid=(l+r)/2;
        if(check(mid))res=mid,l=mid+1;
        else r=mid-1;
    }
    long long ans=0,sum=0;
    for(int i=1;i<=n;i++){
        long long tmp=(res+p[i])/(2*p[i]);
        ans+=tmp,sum+=tmp*tmp*p[i];
        q.push((tmp*2+1)*p[i]);
    }
    m-=sum;
    while(!q.empty()&&m>=q.top())
        m-=q.top(),ans++,q.pop();
    cout<<ans;
    return 0;
}
